	('3d981e74-6b97-4a9e-b79a-2a73634109da', 'c5d30a55-8d9a-46e6-b8d0-6accc0415c1c', 'middle_school', 'diagnostic_screener', NULL, 3, '{3,3,3,3}', 4, 0, 4, '[{"id": "middle_school_diagnostic_d3_numerical_reasoning_1769768519126_3ump5n", "text": "A bakery sells cookies in packs of 8. If a customer wants to buy 56 cookies, how many packs should they purchase?", "phase": "diagnostic", "subtag": "numerical_reasoning", "options": {"A": "5", "B": "6", "C": "7", "D": "8"}, "createdAt": "2026-01-30T10:21:59.127Z", "difficulty": 3, "gradeLevel": "middle_school", "explanation": "To find the number of packs, divide the total number of cookies (56) by the number of cookies per pack (8): 56 / 8 = 7 packs.", "correctAnswer": "C"}, {"id": "middle_school_diagnostic_d3_logical_reasoning_1769768519128_3t75bi", "text": "If all cats like fish and Mittens is a cat, then which of the following must be true?", "phase": "diagnostic", "subtag": "logical_reasoning", "options": {"A": "Mittens likes birds.", "B": "Mittens likes fish.", "C": "All animals like fish.", "D": "Mittens is a dog."}, "createdAt": "2026-01-30T10:21:59.128Z", "difficulty": 3, "gradeLevel": "middle_school", "explanation": "The statement ''all cats like fish'' and ''Mittens is a cat'' leads to the conclusion that Mittens likes fish.", "correctAnswer": "B"}, {"id": "middle_school_diagnostic_d3_verbal_reasoning_1769768519128_5m2tm4", "text": "Which word best completes the following analogy: Happy is to Sad as Fast is to ______?", "phase": "diagnostic", "subtag": "verbal_reasoning", "options": {"A": "Slow", "B": "Quick", "C": "Rabbit", "D": "Race"}, "createdAt": "2026-01-30T10:21:59.128Z", "difficulty": 3, "gradeLevel": "middle_school", "explanation": "Happy and Sad are antonyms (opposites). Fast and Slow are also antonyms.", "correctAnswer": "A"}, {"id": "middle_school_diagnostic_d3_spatial_reasoning_1769768519128_twjzeu", "text": "Which of the following shapes is different from the others?", "phase": "diagnostic", "subtag": "spatial_reasoning", "options": {"A": "Square", "B": "Rectangle", "C": "Triangle", "D": "Circle"}, "createdAt": "2026-01-30T10:21:59.128Z", "difficulty": 3, "gradeLevel": "middle_school", "explanation": "A, B and C are polygons (straight sides), while a circle is curved.", "correctAnswer": "D"}, {"id": "middle_school_diagnostic_d3_data_interpretation_1769768519128_8axs4f", "text": "The following chart shows the number of students in each grade at a school: Grade 6: 80 students, Grade 7: 75 students, Grade 8: 90 students. Which grade has the most students?", "phase": "diagnostic", "subtag": "data_interpretation", "options": {"A": "Grade 6", "B": "Grade 7", "C": "Grade 8", "D": "All grades have the same number of students"}, "createdAt": "2026-01-30T10:21:59.128Z", "difficulty": 3, "gradeLevel": "middle_school", "explanation": "Grade 8 has 90 students, which is more than Grade 6 (80) and Grade 7 (75).", "correctAnswer": "C"}, {"id": "middle_school_diagnostic_d3_pattern_recognition_1769768519128_d2hx2v", "text": "What is the next shape in this pattern: Circle, Square, Triangle, Circle, Square, ______?", "phase": "diagnostic", "subtag": "pattern_recognition", "options": {"A": "Rectangle", "B": "Triangle", "C": "Circle", "D": "Pentagon"}, "createdAt": "2026-01-30T10:21:59.128Z", "difficulty": 3, "gradeLevel": "middle_school", "explanation": "The pattern repeats: Circle, Square, Triangle. Therefore, the next shape is Triangle.", "correctAnswer": "B"}, {"id": "middle_school_diagnostic_d3_numerical_reasoning_1769768519128_wieyxi", "text": "A store is selling notebooks for $3 each. If Sarah buys 7 notebooks and gives the cashier a $25 bill, how much change will she receive?", "phase": "diagnostic", "subtag": "numerical_reasoning", "options": {"A": "$3", "B": "$4", "C": "$5", "D": "$6"}, "createdAt": "2026-01-30T10:21:59.128Z", "difficulty": 3, "gradeLevel": "middle_school", "explanation": "7 notebooks cost 7 * $3 = $21. Her change is $25 - $21 = $4.", "correctAnswer": "B"}, {"id": "middle_school_diagnostic_d3_logical_reasoning_1769768519128_ag34q4", "text": "Some dogs bark loudly. Max is a dog. Therefore, Max ____.", "phase": "diagnostic", "subtag": "logical_reasoning", "options": {"A": "barks softly", "B": "barks loudly", "C": "might bark loudly", "D": "is a cat"}, "createdAt": "2026-01-30T10:21:59.128Z", "difficulty": 3, "gradeLevel": "middle_school", "explanation": "The statement ''some dogs bark loudly'' means it''s possible for a dog to bark loudly, but not guaranteed. Therefore, Max might bark loudly.", "correctAnswer": "C"}]', NULL, 'in_progress', '2026-01-30 10:21:59.594068+00', '2026-01-30 10:22:35.723398+00', NULL),
	('0ede676a-04f8-4a2f-b944-38dfb9a812b6', 'c5d30a55-8d9a-46e6-b8d0-6accc0415c1c', 'higher_secondary', 'stability_confirmation', 'L', 1, '{3,3,3,3,3,3,3,3,2,1,2,1,2,3,2,1,1,2,3,2,1,1,2,1,1,1,1,1}', 28, 10, 5, '[{"id": "higher_secondary_stability_dundefined_numerical_reasoning_1769896743486_1gxqs4", "text": "If a bag contains 5 red, 3 blue, and 4 green marbles, what is the probability of drawing a blue marble?", "phase": "stability", "subtag": "numerical_reasoning", "options": {"A": "3/12", "B": "1/4", "C": "2/5", "D": "3/10"}, "createdAt": "2026-01-31T21:59:03.486Z", "gradeLevel": "higher_secondary", "explanation": "There are 3 blue marbles out of a total of 12 marbles, so the probability is 3/12 or 1/4.", "correctAnswer": "B"}, {"id": "higher_secondary_stability_dundefined_logical_reasoning_1769896743486_gzf5bt", "text": "Which number logically continues the series: 3, 6, 9, 12, 15, ...?", "phase": "stability", "subtag": "logical_reasoning", "options": {"A": "16", "B": "17", "C": "18", "D": "19"}, "createdAt": "2026-01-31T21:59:03.486Z", "gradeLevel": "higher_secondary", "explanation": "The series increases by 3 each time, so the next number is 15 + 3 = 18.", "correctAnswer": "C"}, {"id": "higher_secondary_stability_dundefined_verbal_reasoning_1769896743486_5404mp", "text": "If EARTH is coded as 518924, how is WORLD coded?", "phase": "stability", "subtag": "verbal_reasoning", "options": {"A": "49516", "B": "45916", "C": "49156", "D": "49561"}, "createdAt": "2026-01-31T21:59:03.486Z", "gradeLevel": "higher_secondary", "explanation": "Assign a unique number to each letter, then follow the coding pattern to find the code for WORLD as 49516.", "correctAnswer": "A"}, {"id": "higher_secondary_stability_dundefined_spatial_reasoning_1769896743486_t6zskz", "text": "Which 3D shape will result from folding and cutting the given net? ![3D shape net image]", "phase": "stability", "subtag": "spatial_reasoning", "options": {"A": "Tetrahedron", "B": "Octahedron", "C": "Cube", "D": "Dodecahedron"}, "createdAt": "2026-01-31T21:59:03.486Z", "gradeLevel": "higher_secondary", "explanation": "The given net corresponds to a Tetrahedron when folded and cut along the edges.", "correctAnswer": "A"}, {"id": "higher_secondary_stability_dundefined_data_interpretation_1769896743486_rosnvr", "text": "The bar graph shows the number of hours spent on various activities in a week. What activity had the highest percentage of time spent?", "phase": "stability", "subtag": "data_interpretation", "options": {"A": "Exercise", "B": "Study", "C": "Sleep", "D": "Socializing"}, "createdAt": "2026-01-31T21:59:03.486Z", "gradeLevel": "higher_secondary", "explanation": "Calculate the percentage of time for each activity and identify the one with the highest percentage.", "correctAnswer": "C"}]', 1, 'completed', '2026-01-31 21:55:15.4363+00', '2026-01-31 21:59:45.761343+00', '2026-01-31 21:59:45.514+00'),
	('62c5a173-c0d6-48b3-ac88-93752e91b221', 'c5d30a55-8d9a-46e6-b8d0-6accc0415c1c', 'middle_school', 'adaptive_core', 'L', 1, '{3,3,3,3,3,3,3,3,2,3,2,1,1,1}', 14, 4, 6, '[{"id": "middle_school_core_d2_numerical_reasoning_1769877337096_grmc0t", "text": "If you save $5 each week, how much will you have after 8 weeks?", "phase": "core", "subtag": "numerical_reasoning", "options": {"A": "$30", "B": "$35", "C": "$40", "D": "$45"}, "createdAt": "2026-01-31T16:35:37.096Z", "difficulty": 2, "gradeLevel": "middle_school", "explanation": "Fallback question", "correctAnswer": "C"}, {"id": "middle_school_core_d2_logical_reasoning_1769877337096_wtp3m2", "text": "If A is taller than B, and B is taller than C, who is the shortest?", "phase": "core", "subtag": "logical_reasoning", "options": {"A": "A", "B": "B", "C": "C", "D": "Cannot tell"}, "createdAt": "2026-01-31T16:35:37.096Z", "difficulty": 2, "gradeLevel": "middle_school", "explanation": "Fallback question", "correctAnswer": "C"}, {"id": "middle_school_core_d2_verbal_reasoning_1769877337097_5uz55u", "text": "HOT is to COLD as DAY is to:", "phase": "core", "subtag": "verbal_reasoning", "options": {"A": "Sun", "B": "Night", "C": "Light", "D": "Morning"}, "createdAt": "2026-01-31T16:35:37.097Z", "difficulty": 2, "gradeLevel": "middle_school", "explanation": "Fallback question", "correctAnswer": "B"}, {"id": "middle_school_core_d2_spatial_reasoning_1769877337097_qmwtbm", "text": "If you cut a square diagonally, what shapes do you get?", "phase": "core", "subtag": "spatial_reasoning", "options": {"A": "Two squares", "B": "Two triangles", "C": "Two rectangles", "D": "Two circles"}, "createdAt": "2026-01-31T16:35:37.097Z", "difficulty": 2, "gradeLevel": "middle_school", "explanation": "Fallback question", "correctAnswer": "B"}, {"id": "middle_school_core_d2_data_interpretation_1769877337097_tcvocc", "text": "If a graph shows Monday: 5 books, Tuesday: 3 books, Wednesday: 7 books read, which day had the most books read?", "phase": "cor